  requestId: Number(request.需求编号 || 0),
  statusPatch: { 受理状态: status, 状态说明: row.状态说明 },
  sideEffects: [
    { kind: 'upsert-table-row', tableId: 'request_intake', sheetName: '需求受理台账', keyField: '需求编号', keyValue: request.需求编号, row },
